mapper.select:
		/*
             SQL ID : BbsRltnDAO.listBbsRltn
             설  명 : 게시판 정보 연결 목록
         */
		SELECT 
			  BBS_ID
			, RLTN_REF_CD
			, CONTS_TYCD
		FROM TB_HOME_BBS_RLTN A


				AND A.BBS_ID = #{bbsId}


				AND A.RLTN_REF_CD = #{rltnRefCd}


				AND A.CONTS_TYCD = #{rltnType}

mapper.insert:
		/*
             SQL ID : BbsRltnDAO.insertBbsRltn
             설  명 : 게시판 정보 연결 등록
         */
		INSERT INTO TB_HOME_BBS_RLTN (
			  BBS_ID
			, RLTN_REF_CD
			, CONTS_TYCD
		) VALUES (
			  #{bbsId}
			, #{rltnRefCd}
			, #{rltnType}
		)

mapper.delete:
		/*
             SQL ID : BbsRltnDAO.deleteBbsRltn
             설  명 : 게시판 정보 연결 삭제
         */
		DELETE FROM TB_HOME_BBS_RLTN
		WHERE BBS_ID = #{bbsId}
		AND RLTN_REF_CD = #{rltnRefCd}

		/*
             SQL ID : BbsRltnDAO.deleteBbsRltnAll
             설  명 : 게시판 정보 연결 전체 삭제
         */
		DELETE FROM TB_HOME_BBS_RLTN
		WHERE BBS_ID = #{bbsId}
